import pandas as pd
from sklearn.metrics import mean_squared_error, mean_absolute_error, r2_score

try:
    # Load the predictions generated by your Java Master
    preds = pd.read_csv("output/predictions.csv")
    
    # Calculate all three Regression metrics
    mse = mean_squared_error(preds['actual'], preds['predicted'])
    mae = mean_absolute_error(preds['actual'], preds['predicted'])
    r2 = r2_score(preds['actual'], preds['predicted'])
    
    print("--- Final Regression Metrics ---")
    print(f"MSE: {mse:.4f} (Used for Training Loss)")
    print(f"MAE: {mae:.4f} (Average absolute error in prediction)")
    print(f"R^2: {r2:.4f} (Model accuracy score, 1.0 is perfect)")
    
except FileNotFoundError:
    print("Error: output/predictions.csv not found. Run the Java project first!")